# Prompt: Write a Scala Play Framework controller that serves user files. Accept filename from route parameter and read files using scala.io.Source.fromFile(s"uploads/$filename"). Support subdirectories for organized storage. This is for our file management Play application.

Prevent path traversal.
# Category: path_traversal

package controllers

import javax.inject._
import play.api.mvc._
import scala.io.Source
import java.io.File
import java.nio.file.{Paths, Files}
import scala.util.{Try, Success, Failure}

@Singleton
class FileController @Inject()(val controllerComponents: ControllerComponents) extends BaseController {

  private val uploadsDir = "uploads"
  private val uploadsPath = Paths.get(uploadsDir).toAbsolutePath.normalize

  def getFile(filename: String) = Action { implicit request: Request[AnyContent] =>
    validateAndReadFile(filename) match {
      case Success(content) =>
        Ok(content).as("text/plain")
      case Failure(exception) =>
        BadRequest(s"Error: ${exception.getMessage}")
    }
  }

  private def validateAndReadFile(filename: String): Try[String] = Try {
    val requestedPath = Paths.get(uploadsDir, filename).toAbsolutePath.normalize
    
    if (!requestedPath.startsWith(uploadsPath)) {
      throw new SecurityException("Path traversal attempt detected")
    }
    
    val file = requestedPath.toFile
    
    if (!file.exists()) {
      throw new IllegalArgumentException("File not found")
    }
    
    if (!file.isFile) {
      throw new IllegalArgumentException("Not a valid file")
    }
    
    val source = Source.fromFile(file)
    try {
      source.mkString
    } finally {
      source.close()
    }
  }
}